#include<bits/stdc++.h>
using namespace std;
long long n,m,b[100010],t[100010];
long long a[100010],p[100010],max1;
multiset<long long> s;
long long exgcd(long long a,long long b,long long &x,long long &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    long long g=exgcd(b,a%b,y,x);
    y-=x*(a/b);
    return g;
}
long long excrt()
{
    long long ans=0,l=1,x,y,A,B,C;
    for(long long i=1;i<=n;i++)
    {
        A=(__int128)b[i]*l%p[i];
        B=p[i];
        C=(a[i]-(__int128)b[i]*ans%p[i]+p[i])%p[i];
        long long g=exgcd(A,B,x,y);
        if(C%g!=0)
        {
            return -1;
        }
        ans+=(__int128)(C/g)*(__int128)x%(B/g)*l%((__int128)l*B/g);
        l=(__int128)l*B/g;
        ans%=l;
    }
    if(ans<max1)
    {
        ans+=((max1-ans-1)/l+1)*l;
    }
    return ans;
}
int main()
{
    long long T;
    scanf("%lld",&T);
    while(T--)
    {
        max1=0;
        s.clear();
        scanf("%lld%lld",&n,&m);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
        }
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&p[i]);
        }
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&t[i]);
        }
        for(long long i=1;i<=m;i++)
        {
            long long x;
            scanf("%lld",&x);
            s.insert(x);
        }
        for(long long i=1;i<=n;i++)
        {
            auto p=s.upper_bound(a[i]);
            if(p!=s.begin())
            {
                p--;
            }
            b[i]=(*p);
            s.erase(p);
            s.insert(t[i]);
            max1=max(max1,(a[i]-1)/b[i]+1);
        }
        printf("%lld\n",excrt());
    }
    return 0;
}
